def run_act(repo: Path) -> tuple[int, str]:
    """Execute `act push --rm` in the given repo. Returns (rc, output)."""
    proc = subprocess.run(
        ["act", "push", "--rm"],
        cwd=repo,
        capture_output=True,
        text=True,
        timeout=600,
    )
    return proc.returncode, (proc.stdout + proc.stderr)

